from langchain.agents import AgentExecutor
from vex import verify

@verify(test_name='agent-loop-detection')
def test_agent_loop(chain: AgentExecutor, input_query: str):
    result = chain.invoke({"input": input_query})
    tool_calls = chain.agent.llm_with_tools.last_token.tool_calls

    # Detect if same tool called >3 times consecutively
    if len(tool_calls) > 3:
        consecutive_same = all(
            tool_calls[i].name == tool_calls[i+1].name 
            for i in range(len(tool_calls)-1)
        )
        if consecutive_same:
            raise AssertionError('Agent loop detected')

    return result

from langchain.chains import RetrievalQA
from langchain.schema import Document

@verify(test_name='rag-hallucination')
def test_rag_hallucination(retriever_chain: RetrievalQA, query: str):
    result = retriever_chain({"query": query})

    generated_content = result['result']
    source_docs = result['source_documents']

    # Check if generated content contains phrases not in source docs
    source_text = ' '.join([doc.page_content for doc in source_docs])
    hallucinated_phrases = [
        phrase for phrase in generated_content.split('. ')
        if phrase.strip() and phrase.lower() not in source_text.lower()
    ]

    if len(hallucinated_phrases) > 2:
        raise AssertionError(f'Hallucination detected: {hallucinated_phrases[:3]}')

    return result

from langchain.chains import ConversationalRetrievalChain
from langchain.callbacks import get_openai_callback

@verify(test_name='context-overflow')
def test_context_window(chain: ConversationalRetrievalChain, chat_history, query):
    with get_openai_callback() as cb:
        result = chain({"question": query, "chat_history": chat_history})

    total_tokens = cb.total_tokens
    if total_tokens > 12000:  # Near GPT-4 limit
        raise AssertionError(f'Context overflow: {total_tokens} tokens used')

    return {'result': result, 'tokens_used': total_tokens}
